// Get all items from Merge (Parse is index 0, Analysis is index 1)
const allItems = $input.all();

// Parse data from first item
const parseItem = allItems[0]?.json || {};
const parsedMarkdown = parseItem.markdown || parseItem.text || 'No content parsed';
const pageCount = parseItem.pageCount || 0;

// Analysis data from second item
const analysisItem = allItems[1]?.json || {};
const policyAnalysis = analysisItem.markdown || analysisItem.answer || analysisItem.text || 'No analysis generated';

// Get trigger data for file info
const triggerData = $('New Regulation').item.json;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Extract regulation name from filename or content
let regulationName = fileName.replace(/\.[^/.]+$/, '').replace(/_/g, ' ');

// Determine jurisdiction from analysis
let jurisdiction = 'Unknown';
const analysisLower = policyAnalysis.toLowerCase();
if (analysisLower.includes('european union') || analysisLower.includes('eu ')) jurisdiction = 'EU';
else if (analysisLower.includes('united states') || analysisLower.includes('federal')) jurisdiction = 'US Federal';
else if (analysisLower.includes('california')) jurisdiction = 'US - California';
else if (analysisLower.includes('colorado')) jurisdiction = 'US - Colorado';
else if (analysisLower.includes('new york')) jurisdiction = 'US - New York';
else if (analysisLower.includes('uk') || analysisLower.includes('united kingdom')) jurisdiction = 'UK';

// Count policy gaps mentioned
let gapCount = 0;
if (analysisLower.includes('gap')) {
  gapCount = (analysisLower.match(/gap/g) || []).length;
}

// Determine priority
let priority = 'Medium';
let criticalCount = (analysisLower.match(/critical/g) || []).length;
let highCount = (analysisLower.match(/high/g) || []).length;

if (criticalCount >= 2) priority = 'Critical';
else if (criticalCount >= 1 || highCount >= 3) priority = 'High';
else if (highCount >= 1) priority = 'Medium';
else priority = 'Low';

// Extract action items count
let actionCount = 0;
const actionMatches = policyAnalysis.match(/\d+\./g);
if (actionMatches) actionCount = actionMatches.length;

return [{
  json: {
    regulationName: regulationName,
    jurisdiction: jurisdiction,
    pageCount: pageCount,
    parsedContent: parsedMarkdown.substring(0, 500) + '...',
    fullParsedContent: parsedMarkdown,
    policyAnalysis: policyAnalysis,
    gapCount: gapCount,
    actionCount: actionCount,
    priority: priority,
    criticalItems: criticalCount,
    highItems: highCount,
    fileName: fileName,
    fileId: fileId,
    processedAt: new Date().toISOString()
  }
}];

